import React from "react";
import { ArrowLeft } from "lucide-react";

export default function PaymentProcessingScreen({ onBack }) {
  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24 flex flex-col items-center justify-center gap-6">
      {/* Back */}
      <button onClick={onBack} className="self-start mb-8">
        <ArrowLeft className="w-6 h-6 text-gray-700" />
      </button>

      {/* Processing card */}
      <div className="bg-white rounded-2xl p-6 shadow-sm flex flex-col items-center gap-4">
        <p className="text-xl font-semibold text-gray-900">
          Processing Payment
        </p>
        <p className="text-gray-500 text-center">
          Please wait while we confirm your transaction.
        </p>
      </div>
    </div>
  );
}
